        SolveResult res;
        char audit[512];
        if (run_named(argv[2], out_dir, &res) != 0) {
            return 1;
        }
        snprintf(audit, sizeof(audit), "/app/output/%s-audit.json", argv[2]);
        return emit_t(&res, audit) != 0;
    }
    fprintf(stderr, "usage: solverctl matrix | solverctl one <case>\n");
    return 1;
}
